// Colores del motor gráfico
export const GOLD  = '#C9A84C';
export const GOLD2 = '#E8C96A';
export const SILVER = '#B8C0CC';
export const DARK = '#0A0A0A';

// Obtiene la lista unificada de productos (estáticos + personalizados) - SSR Safe
export const DEFAULT_CATEGORIAS = [
  { id: 'todos', emoji: '✨', nombre: 'Todos' },
  { id: 'madre', emoji: '👩', nombre: 'Día de la Madre' },
  { id: 'padre', emoji: '👨', nombre: 'Día del Padre' },
  { id: 'parejas', emoji: '❤️', nombre: 'Parejas' },
  { id: 'spotify', emoji: '🎵', nombre: 'Estilo Spotify' },
  { id: 'bebes', emoji: '👶', nombre: 'Bebés' },
  { id: 'netflix', emoji: '🎬', nombre: 'Estilo Netflix' },
  { id: 'collage', emoji: '🖼️', nombre: 'Collage' },
  { id: 'familia', emoji: '🏠', nombre: 'Familia' },
  { id: 'otros', emoji: '✦', nombre: 'Otros' }
];

export function getCategoriasList() {
  if (typeof window === 'undefined') {
    return DEFAULT_CATEGORIAS;
  }
  try {
    const raw = localStorage.getItem('colkley_categorias:v1');
    return raw ? JSON.parse(raw) : DEFAULT_CATEGORIAS;
  } catch (e) {
    console.error("Error reading categories list", e);
    return DEFAULT_CATEGORIAS;
  }
}

export const DEFAULT_GIFT_WRAP_CONFIG = {
  enabled: true,
  price: 2500,
  fields: [
    { id: 'field_paper', label: 'Estilo de envoltura', type: 'select', options: ['Papel Dorado Elegante', 'Papel Kraft Rústico', 'Papel Infantil Navideño'], required: true },
    { id: 'field_message', label: 'Mensaje para la dedicatoria', type: 'textarea', placeholder: 'Escribe tu mensaje con amor...', required: false }
  ]
};

export function getGiftWrapConfig() {
  if (typeof window === 'undefined') {
    return DEFAULT_GIFT_WRAP_CONFIG;
  }
  try {
    const raw = localStorage.getItem('colkley_gift_wrap_config:v1');
    if (!raw) return DEFAULT_GIFT_WRAP_CONFIG;
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== 'object' || !parsed.fields || typeof parsed.price !== 'number') {
      return DEFAULT_GIFT_WRAP_CONFIG;
    }
    return parsed;
  } catch (e) {
    console.error("Error reading gift wrap config", e);
    return DEFAULT_GIFT_WRAP_CONFIG;
  }
}

export function getDeletedStaticIds() {
  if (typeof window === 'undefined') return [];
  try {
    const raw = localStorage.getItem('colkley_deleted_static_ids:v1');
    return raw ? JSON.parse(raw) : [];
  } catch (e) {
    console.error("Error reading deleted static ids", e);
    return [];
  }
}

export function getProductos() {
  if (typeof window === 'undefined') {
    return productos;
  }
  try {
    const deletedStaticIds = getDeletedStaticIds();
    const custom = localStorage.getItem('colkley_custom_productos:v1');
    const customList = custom ? JSON.parse(custom) : [];
    
    // Filtrar los estáticos eliminados
    const activeStatic = productos.filter(p => !deletedStaticIds.includes(p.id));

    // Unificar reemplazando los estáticos que tengan una versión editada (mismo ID)
    const result = activeStatic.map(staticProd => {
      const edited = customList.find(c => c.id === staticProd.id);
      return edited || staticProd;
    });
    
    // Y agregar los personalizados completamente nuevos (que no coinciden con ningún ID estático)
    const staticIds = productos.map(p => p.id);
    const brandNewCustoms = customList
      .filter(c => !staticIds.includes(c.id))
      .map(p => {
        // Migración autocorrectiva en renderizado para que los marcos nuevos tengan su nombre como diseño y salgan en el filtro
        if (p.tipo === 'marco' && p.diseño === 'nordic_frame') {
          return { ...p, diseño: p.nombre };
        }
        return p;
      });
    
    return [...result, ...brandNewCustoms];
  } catch (e) {
    console.error("Error al unificar productos", e);
    return productos;
  }
}

// Dibuja el área de foto dentro del cuadro
export function dibujarAreaFoto(ctx, diseño, w, h) {
  const pad = w * 0.1;
  switch(diseño) {
    case 'roca':
      ctx.beginPath();
      ctx.moveTo(pad * 1.2, pad);
      ctx.lineTo(w - pad * 0.8, pad * 0.8);
      ctx.lineTo(w - pad * 0.6, h - pad);
      ctx.lineTo(pad * 0.9, h - pad * 1.1);
      ctx.closePath();
      break;
    case 'taza':
      const tw = w * 0.6, th = h * 0.42;
      const tx = (w - tw) / 2, ty = (h - th) / 2 - h * 0.05;
      ctx.beginPath();
      ctx.rect(tx, ty, tw, th);
      break;
    case 'llavero':
      ctx.beginPath();
      ctx.arc(w/2, h/2 + 10, w * 0.28, 0, Math.PI * 2);
      break;
    default:
      ctx.beginPath();
      ctx.rect(pad, pad, w - pad*2, h - pad*2);
  }
}

// Dibuja el marco encima del cuadro
export function superponeMarco(ctx, diseño, w, h) {
  ctx.save();
  switch(diseño) {
    case 'dorado':
      ctx.strokeStyle = GOLD;
      ctx.lineWidth = w * 0.055;
      ctx.strokeRect(6, 6, w-12, h-12);
      ctx.strokeStyle = GOLD2;
      ctx.lineWidth = 1.5;
      ctx.strokeRect(w*0.09, w*0.09, w-w*0.18, h-w*0.18);
      ctx.strokeStyle = GOLD;
      ctx.lineWidth = 0.8;
      ctx.strokeRect(w*0.12, w*0.12, w-w*0.24, h-w*0.24);
      [[w*0.09,w*0.09],[w-w*0.09,w*0.09],[w*0.09,h-w*0.09],[w-w*0.09,h-w*0.09]].forEach(([cx,cy]) => {
        ctx.beginPath(); ctx.arc(cx,cy,3,0,Math.PI*2);
        ctx.fillStyle = GOLD2; ctx.fill();
      });
      break;

    case 'collage':
      ctx.strokeStyle = '#0A0A0A';
      ctx.lineWidth = w * 0.08;
      ctx.strokeRect(4, 4, w-8, h-8);
      ctx.strokeStyle = GOLD;
      ctx.lineWidth = 1.5;
      ctx.strokeRect(w*0.09, w*0.09, w-w*0.18, h-w*0.18);
      ctx.fillStyle = 'rgba(0,0,0,0.55)';
      ctx.fillRect(w*0.12, h*0.72, w*0.76, h*0.18);
      ctx.fillStyle = GOLD2;
      ctx.font = `italic ${w*0.065}px Cormorant Garamond, serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('✦ Colkley ✦', w/2, h*0.81);
      break;

    case 'roca':
      ctx.strokeStyle = GOLD;
      ctx.lineWidth = 2.5;
      ctx.beginPath();
      const pad = w*0.1;
      ctx.moveTo(pad*1.2, pad);
      ctx.lineTo(w-pad*0.8, pad*0.8);
      ctx.lineTo(w-pad*0.6, h-pad);
      ctx.lineTo(pad*0.9, h-pad*1.1);
      ctx.closePath();
      ctx.stroke();
      ctx.fillStyle = GOLD;
      ctx.font = `${w*0.06}px Cinzel, serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'bottom';
      ctx.fillText('COLKLEY', w/2, h - 8);
      break;

    case 'taza':
      ctx.strokeStyle = GOLD;
      ctx.lineWidth = 2.5;
      const TW = w*0.68, TH = h*0.52;
      const TX = (w-TW)/2, TY = (h-TH)/2 - h*0.05;
      ctx.beginPath();
      ctx.moveTo(TX, TY);
      ctx.lineTo(TX + TW*0.04, TY + TH);
      ctx.lineTo(TX + TW*0.96, TY + TH);
      ctx.lineTo(TX + TW, TY);
      ctx.arc(TX + TW/2, TY, TW/2, 0, Math.PI, true);
      ctx.stroke();
      ctx.beginPath();
      ctx.arc(TX + TW + 10, TY + TH*0.4, 16, -Math.PI*0.45, Math.PI*0.45);
      ctx.stroke();
      ctx.fillStyle = GOLD;
      ctx.font = `${w*0.056}px Cinzel, serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('COLKLEY', w/2, TY + TH + 22);
      break;

    case 'llavero':
      ctx.strokeStyle = GOLD;
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.arc(w/2, h/2+10, w*0.28, 0, Math.PI*2);
      ctx.stroke();
      ctx.strokeStyle = GOLD2;
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.arc(w/2, h/2+10, w*0.31, 0, Math.PI*2);
      ctx.stroke();
      ctx.strokeStyle = SILVER;
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.arc(w/2, h/2 - w*0.25, 12, 0, Math.PI*2);
      ctx.stroke();
      break;

    case 'restauracion':
      ctx.strokeStyle = GOLD;
      ctx.lineWidth = 2;
      ctx.strokeRect(w*0.08, w*0.08, w-w*0.16, h-w*0.16);
      ctx.strokeStyle = 'rgba(201,168,76,0.4)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(w*0.08, h*0.5);
      ctx.lineTo(w-w*0.08, h*0.5);
      ctx.stroke();
      ctx.fillStyle = 'rgba(10,10,10,0.6)';
      ctx.fillRect(w*0.08, h*0.08, w-w*0.16, h*0.16);
      ctx.fillStyle = GOLD2;
      ctx.font = `${w*0.058}px Cinzel, serif`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('RESTAURACIÓN', w/2, h*0.16);
      break;
  }
  ctx.restore();
}

// Dibuja el diseño completo (recibe las imágenes cargadas como argumentos para evitar ReferenceErrors en SSR)
export function dibujarDiseño(ctx, diseño, w, h, imgUsuario, maquetas = {}) {
  ctx.clearRect(0, 0, w, h);
  ctx.fillStyle = '#141414';
  ctx.fillRect(0, 0, w, h);

  if (diseño === 'spotify_negro') {
    const win_x = w * (311 / 1044.0);
    const win_y = h * (198 / 1024.0);
    const win_w = w * (437 / 1044.0);
    const win_h = h * (435 / 1024.0);

    if (imgUsuario) {
      ctx.save();
      ctx.beginPath();
      ctx.rect(win_x, win_y, win_w, win_h);
      ctx.clip();
      const ar = imgUsuario.width / imgUsuario.height;
      let sw = win_w, sh = sw / ar;
      if (sh < win_h) { sh = win_h; sw = sh * ar; }
      const sx = win_x + (win_w - sw) / 2;
      const sy = win_y + (win_h - sh) / 2;
      ctx.drawImage(imgUsuario, sx, sy, sw, sh);
      ctx.restore();
    } else {
      ctx.fillStyle = '#1E1E1E';
      ctx.fillRect(win_x, win_y, win_w, win_h);
      ctx.fillStyle = '#666';
      ctx.font = `${w*0.045}px Montserrat`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('Tu foto aquí', win_x + win_w/2, win_y + win_h/2 - 8);
      ctx.font = `${w*0.06}px sans-serif`;
      ctx.fillText('📷', win_x + win_w/2, win_y + win_h/2 + 15);
    }

    const templateImg = maquetas.spotify_negro;
    if (templateImg && templateImg.complete && templateImg.naturalWidth !== 0) {
      ctx.drawImage(templateImg, 0, 0, w, h);
    } else {
      ctx.strokeStyle = 'rgba(201,168,76,0.3)';
      ctx.lineWidth = 1;
      ctx.strokeRect(win_x, win_y, win_w, win_h);
      ctx.fillStyle = '#C9A84C';
      ctx.font = `${w*0.035}px Cinzel, serif`;
      ctx.textAlign = 'center';
      ctx.fillText('Cargando plantilla...', w/2, h/2);
    }
    return;
  }

  if (diseño === 'nordic_frame') {
    const img_ar = 4500.0 / 3000.0;
    const canvas_ar = w / h;
    let dw = w, dh = h;
    let dx = 0, dy = 0;
    
    if (img_ar > canvas_ar) {
      dw = h * img_ar;
      dx = (w - dw) / 2;
    } else {
      dh = w / img_ar;
      dy = (h - dh) / 2;
    }

    const win_x = dx + dw * (2106 / 4500.0);
    const win_y = dy + dh * (868 / 3000.0);
    const win_w = dw * (737 / 4500.0);
    const win_h = dh * (927 / 3000.0);

    if (imgUsuario) {
      ctx.save();
      ctx.beginPath();
      ctx.rect(win_x, win_y, win_w, win_h);
      ctx.clip();
      const ar = imgUsuario.width / imgUsuario.height;
      let sw = win_w, sh = sw / ar;
      if (sh < win_h) { sh = win_h; sw = sh * ar; }
      const sx = win_x + (win_w - sw) / 2;
      const sy = win_y + (win_h - sh) / 2;
      ctx.drawImage(imgUsuario, sx, sy, sw, sh);
      ctx.restore();
    } else {
      ctx.fillStyle = '#1E1E1E';
      ctx.fillRect(win_x, win_y, win_w, win_h);
      ctx.fillStyle = '#666';
      ctx.font = `${w*0.032}px Montserrat`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('Tu foto aquí', win_x + win_w/2, win_y + win_h/2 - 8);
      ctx.font = `${w*0.045}px sans-serif`;
      ctx.fillText('📷', win_x + win_w/2, win_y + win_h/2 + 12);
    }

    const templateImg = maquetas.nordic_frame;
    if (templateImg && templateImg.complete && templateImg.naturalWidth !== 0) {
      ctx.drawImage(templateImg, dx, dy, dw, dh);
    } else {
      ctx.strokeStyle = 'rgba(201,168,76,0.3)';
      ctx.lineWidth = 1;
      ctx.strokeRect(win_x, win_y, win_w, win_h);
      ctx.fillStyle = '#C9A84C';
      ctx.font = `${w*0.035}px Cinzel, serif`;
      ctx.textAlign = 'center';
      ctx.fillText('Cargando maqueta...', w/2, h/2);
    }
    return;
  }

  if (diseño === 'nordic_room') {
    const img_ar = 4000.0 / 2660.0;
    const canvas_ar = w / h;
    let dw = w, dh = h;
    let dx = 0, dy = 0;
    
    if (img_ar > canvas_ar) {
      dw = h * img_ar;
      dx = (w - dw) / 2;
    } else {
      dh = w / img_ar;
      dy = (h - dh) / 2;
    }

    const win_x = dx + dw * (1356 / 4000.0);
    const win_y = dy + dh * (420 / 2660.0);
    const win_w = dw * (1357 / 4000.0);
    const win_h = dh * (1831 / 2660.0);

    if (imgUsuario) {
      ctx.save();
      ctx.beginPath();
      ctx.rect(win_x, win_y, win_w, win_h);
      ctx.clip();
      const ar = imgUsuario.width / imgUsuario.height;
      let sw = win_w, sh = sw / ar;
      if (sh < win_h) { sh = win_h; sw = sh * ar; }
      const sx = win_x + (win_w - sw) / 2;
      const sy = win_y + (win_h - sh) / 2;
      ctx.drawImage(imgUsuario, sx, sy, sw, sh);
      ctx.restore();
    } else {
      ctx.fillStyle = '#1E1E1E';
      ctx.fillRect(win_x, win_y, win_w, win_h);
      ctx.fillStyle = '#666';
      ctx.font = `${w*0.032}px Montserrat`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('Tu foto aquí', win_x + win_w/2, win_y + win_h/2 - 8);
      ctx.font = `${w*0.045}px sans-serif`;
      ctx.fillText('📷', win_x + win_w/2, win_y + win_h/2 + 12);
    }

    const templateImg = maquetas.nordic_room;
    if (templateImg && templateImg.complete && templateImg.naturalWidth !== 0) {
      ctx.drawImage(templateImg, dx, dy, dw, dh);
    } else {
      ctx.strokeStyle = 'rgba(201,168,76,0.3)';
      ctx.lineWidth = 1;
      ctx.strokeRect(win_x, win_y, win_w, win_h);
      ctx.fillStyle = '#C9A84C';
      ctx.font = `${w*0.035}px Cinzel, serif`;
      ctx.textAlign = 'center';
      ctx.fillText('Cargando maqueta...', w/2, h/2);
    }
    return;
  }

  if (imgUsuario) {
    ctx.save();
    dibujarAreaFoto(ctx, diseño, w, h);
    ctx.clip();
    const ar = imgUsuario.width / imgUsuario.height;
    let sw = w * 0.78, sh = sw / ar;
    if (sh > h * 0.78) { sh = h * 0.78; sw = sh * ar; }
    const sx = (w - sw) / 2, sy = (h - sh) / 2;
    ctx.drawImage(imgUsuario, sx, sy, sw, sh);
    ctx.restore();
  } else {
    ctx.save();
    dibujarAreaFoto(ctx, diseño, w, h);
    ctx.clip();
    ctx.fillStyle = '#1E1E1E';
    ctx.fillRect(0, 0, w, h);
    ctx.fillStyle = '#333';
    ctx.font = `${w*0.07}px Montserrat`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('Tu foto aquí', w/2, h/2 - 10);
    ctx.font = `${w*0.09}px sans-serif`;
    ctx.fillText('📷', w/2, h/2 + 22);
    ctx.restore();
  }

  superponeMarco(ctx, diseño, w, h);
}
